patch:
diff --git a/llvm/lib/Transforms/InstCombine/InstCombineCalls.cpp b/llvm/lib/Transforms/InstCombine/InstCombineCalls.cpp
index 33b66aeaffe6..c3e8d2c717c2 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineCalls.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineCalls.cpp
@@ -2931,6 +2931,17 @@ Instruction *InstCombinerImpl::visitCallInst(CallInst &CI) {
           Builder.CreateUnaryIntrinsic(Intrinsic::fabs, Magnitude, II);
       return replaceInstUsesWith(*II, AbsSign);
     }
+    // fabs (fadd X, 0.0) -> fabs X
+    // fabs (fadd 0.0, X) -> fabs X
+    // fabs (fsub X, 0.0) -> fabs X
+    // fabs (fsub 0.0, X) -> fabs X
+    // Because fabs discards sign, signed zero considerations are irrelevant.
+    if (match(Arg, m_FAdd(m_Value(X), m_AnyZeroFP())) ||
+        match(Arg, m_FAdd(m_AnyZeroFP(), m_Value(X))) ||
+        match(Arg, m_FSub(m_Value(X), m_AnyZeroFP())) ||
+        match(Arg, m_FSub(m_AnyZeroFP(), m_Value(X)))) {
+      return replaceOperand(*II, 0, X);
+    }

     [[fallthrough]];
   }

